command:
set -euo pipefail; export SRC_DB="$SOURCE_DATABASE_URL"; export DST_DB="$TARGET_DATABASE_URL"; echo "preparing target auth stubs and extensions"; psql "$DST_DB" -v ON_ERROR_STOP=1 <<'SQL'
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'casaora_migrator') THEN
    CREATE ROLE casaora_migrator;
  END IF;
END
$$;
DROP EXTENSION IF EXISTS vector CASCADE;
DROP EXTENSION IF EXISTS pg_trgm CASCADE;
DROP EXTENSION IF EXISTS btree_gist CASCADE;
DROP EXTENSION IF EXISTS citext CASCADE;
DROP EXTENSION IF EXISTS "uuid-ossp" CASCADE;
DROP EXTENSION IF EXISTS pgcrypto CASCADE;
CREATE SCHEMA IF NOT EXISTS extensions;
CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS "uuid-ossp" WITH SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS btree_gist WITH SCHEMA public;
CREATE EXTENSION IF NOT EXISTS citext WITH SCHEMA public;
CREATE EXTENSION IF NOT EXISTS pg_trgm WITH SCHEMA public;
CREATE EXTENSION IF NOT EXISTS vector WITH SCHEMA public;
CREATE SCHEMA IF NOT EXISTS auth;
CREATE OR REPLACE FUNCTION auth.uid() RETURNS uuid LANGUAGE sql STABLE AS $$ SELECT NULL::uuid $$;
CREATE OR REPLACE FUNCTION auth.role() RETURNS text LANGUAGE sql STABLE AS $$ SELECT NULL::text $$;
CREATE OR REPLACE FUNCTION auth.jwt() RETURNS jsonb LANGUAGE sql STABLE AS $$ SELECT '{}'::jsonb $$;
SQL
echo "dumping supabase public schema+data"; pg_dump "$SRC_DB" --enable-row-security --no-owner --no-acl --format=custom --compress=0 --schema=public --file=/tmp/public.dump; echo "filtering restore toc to keep existing public schema"; pg_restore -l /tmp/public.dump > /tmp/public.toc; grep -Ev ' (SCHEMA|COMMENT - SCHEMA|ACL - SCHEMA) - public( |$)' /tmp/public.toc > /tmp/public.filtered.toc || cp /tmp/public.toc /tmp/public.filtered.toc; echo "restoring into rds"; pg_restore --dbname="$DST_DB" --no-owner --no-acl --clean --if-exists --exit-on-error --use-list=/tmp/public.filtered.toc /tmp/public.dump; echo "disabling RLS on target public tables"; psql "$DST_DB" -v ON_ERROR_STOP=1 <<'SQL'
DO $$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT n.nspname AS schema_name, c.relname AS table_name
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public'
      AND c.relkind = 'r'
      AND c.relrowsecurity = true
  LOOP
    EXECUTE format('ALTER TABLE %I.%I DISABLE ROW LEVEL SECURITY', r.schema_name, r.table_name);
  END LOOP;
END
$$;
SQL
echo "vacuum analyze"; psql "$DST_DB" -v ON_ERROR_STOP=1 -c 'ANALYZE;'
